date.setMonth(date.getMonth() - 1); // Restamos 1 mes a la fecha actual

const year = date.getFullYear();
// getMonth() devuelve 0-11, sumamos 1 y usamos padStart para asegurar 2 dígitos (ej: '02')
const month = String(date.getMonth() + 1).padStart(2, '0'); 

const folderName = `${year}_${month}`; 
// Resultado esperado: Si corre en Marzo 2026 -> folderName = "2026_02"

return environments.map(env => ({
  json: {
    env,
    zipName: folderName,
    // Ruta interna del contenedor
    basePath: `/files_host/XML_Mails_error/${env}`
  }
}));

// Parsear salida de grep (CORREGIDO)
try {
  // Usamos .item para asegurar que leemos el ambiente ACTUAL, no el primero
  const loopNode = $('Loop x Ambiente');
  // Fallback seguro: intentar leer .item, si falla, leer .json directo si el nodo anterior pasó la info
  const loopData = loopNode.item ? loopNode.item.json : (loopNode.first ? loopNode.first().json : {});

  const env = loopData.env || 'UNKNOWN';
  const zipName = loopData.zipName;
  const basePath = loopData.basePath;

  const item = items[0];
  const stdout = (item && item.json && item.json.stdout) ? item.json.stdout : '';

  // Si stdout está vacío, es SKIP o dice NO_MATCHES
  if (!stdout || stdout.includes('SKIP') || stdout.includes('NO_MATCHES') || stdout.trim() === '') {
    return [{
      json: {
        env, zipName, basePath, files: [] 
      }
    }];
  }

  const lines = stdout.split('\n').filter(l => l.trim() !== '');
  const byFile = new Map();

  for (const line of lines) {
    const colonIndex = line.indexOf(':');
    if (colonIndex === -1) continue;

    const filePath = line.slice(0, colonIndex);
    const match = line.slice(colonIndex + 1);
    const cleanPath = filePath.replace(/\\/g, '/');

    const entry = byFile.get(cleanPath) || { filePath: cleanPath, MailFrom: [], MailTo: [] };

    if (match.includes('<MailFrom>')) {
      const val = (match.match(/<MailFrom>([^<]*)<\/MailFrom>/i) || [])[1] || '';
      entry.MailFrom.push(val);
    } else if (match.includes('<MailTo>')) {
      const val = (match.match(/<MailTo>([^<]*)<\/MailTo>/i) || [])[1] || '';
      entry.MailTo.push(val);
    }
    byFile.set(cleanPath, entry);
  }

  const consolidated = Array.from(byFile.values()).map(r => ({
    env,
    zipName,
    basePath,
    archivo: r.filePath.split('/').pop(),
    MailFrom: r.MailFrom.length ? r.MailFrom[0] : 'NO_ENCONTRADO',
    MailTo: r.MailTo.length ? r.MailTo[0] : 'NO_ENCONTRADO'
  }));

  if (consolidated.length === 0) {
      return [{ json: { env, zipName, basePath, files: [] } }];
  }

  return [{ json: { env, zipName, basePath, files: consolidated } }];

} catch (error) {
  return [{
      json: {
        env: 'ERROR_CATCH',
        files: [] 
      }
  }];
}

// Prepara filas para CSV
const payload = items[0].json;
const files = payload.files || [];

const rows = files.map(f => ({
  json: {
    Archivo: f.archivo,
    MailFrom: f.MailFrom,
    MailTo: f.MailTo,
